// Quality control check
const article = $input.item.json.article;

// Check word count
const wordCount = article.split(' ').length;
if (wordCount < 1500) {
  throw new Error('Article too short: ' + wordCount + ' words');
}

// Check readability (simple Flesch score approximation)
const sentences = article.split(/[.!?]+/).length;
const words = article.split(' ').length;
const syllables = words * 1.5; // Rough estimate

const fleschScore = 206.835 - 1.015 * (words / sentences) - 84.6 * (syllables / words);

if (fleschScore < 50 || fleschScore > 80) {
  $input.item.json.warning = 'Readability score outside target range: ' + fleschScore;
}

// Check keyword density
const keywords = ['política', 'argentina', 'economía', 'noticias'];
let keywordCount = 0;
keywords.forEach(kw => {
  const regex = new RegExp(kw, 'gi');
  keywordCount += (article.match(regex) || []).length;
});

const keywordDensity = (keywordCount / words) * 100;
if (keywordDensity > 3) {
  throw new Error('Keyword stuffing detected: ' + keywordDensity + '%');
}

$input.item.json.quality_metrics = {
  word_count: wordCount,
  flesch_score: fleschScore,
  keyword_density: keywordDensity
};

return $input.item;

// Generate meta tags
const article = $input.item.json.article;
const title = $input.item.json.title;

// Meta description (150-160 characters)
const firstSentence = article.split('.')[0] + '.';
const metaDescription = firstSentence.substring(0, 157) + '...';

// SEO title (50-60 characters)
const seoTitle = title.length > 60 ? title.substring(0, 57) + '...' : title;

$input.item.json.seo = {
  title: seoTitle,
  description: metaDescription,
  keywords: $input.item.json.keywords,
  og_title: title,
  og_description: metaDescription,
  og_type: 'article',
  twitter_card: 'summary_large_image'
};

return $input.item;

// Randomly select one of 15 PBN sites
const pbnSites = [
  // Tier 1: Authority Domains (DA 85-90)
  { tier: 1, site: 'https://expired-news-argentina-1.com', wp_api: 'https://expired-news-argentina-1.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T1_1_PASS },
  { tier: 1, site: 'https://political-analysis-ar.com', wp_api: 'https://political-analysis-ar.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T1_2_PASS },
  { tier: 1, site: 'https://economia-argentina-news.com', wp_api: 'https://economia-argentina-news.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T1_3_PASS },
  { tier: 1, site: 'https://breaking-news-ba.com', wp_api: 'https://breaking-news-ba.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T1_4_PASS },
  { tier: 1, site: 'https://argentina-politics-today.com', wp_api: 'https://argentina-politics-today.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T1_5_PASS },

  // Tier 2: Regional Domains (DA 75-84)
  { tier: 2, site: 'https://noticias-buenos-aires-24.com', wp_api: 'https://noticias-buenos-aires-24.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T2_1_PASS },
  { tier: 2, site: 'https://cordoba-informacion.com', wp_api: 'https://cordoba-informacion.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T2_2_PASS },
  { tier: 2, site: 'https://rosario-noticias-hoy.com', wp_api: 'https://rosario-noticias-hoy.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T2_3_PASS },
  { tier: 2, site: 'https://mendoza-al-dia.com', wp_api: 'https://mendoza-al-dia.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T2_4_PASS },
  { tier: 2, site: 'https://tucuman-actualidad.com', wp_api: 'https://tucuman-actualidad.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T2_5_PASS },

  // Tier 3: Niche Domains (DA 70-79)
  { tier: 3, site: 'https://economia-argentina-analysis.com', wp_api: 'https://economia-argentina-analysis.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T3_1_PASS },
  { tier: 3, site: 'https://politica-opinion-ar.com', wp_api: 'https://politica-opinion-ar.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T3_2_PASS },
  { tier: 3, site: 'https://deportes-argentina-live.com', wp_api: 'https://deportes-argentina-live.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T3_3_PASS },
  { tier: 3, site: 'https://cultura-argentina-magazine.com', wp_api: 'https://cultura-argentina-magazine.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T3_4_PASS },
  { tier: 3, site: 'https://tecnologia-innovacion-ar.com', wp_api: 'https://tecnologia-innovacion-ar.com/wp-json/wp/v2/', username: 'admin', password: process.env.PBN_T3_5_PASS }
];

const randomIndex = Math.floor(Math.random() * pbnSites.length);
$input.item.json.pbn = pbnSites[randomIndex];

return $input.item;

// Decide if this article should link to main site (5% probability)
const shouldLink = Math.random() < 0.05; // 5% chance

if (shouldLink) {
  const anchorTextOptions = [
    // Branded (40%)
    'POLÍTICA ARGENTINA',
    'politica-argentina.com',
    'portal POLÍTICA ARGENTINA',

    // Naked URL (20%)
    'politica-argentina.com',
    'https://politica-argentina.com',

    // Generic (20%)
    'este artículo',
    'fuente',
    'más información',
    'leer más',

    // Exact Match (10%)
    'noticias argentina',
    'política argentina hoy',

    // Partial Match (10%)
    'noticias de política en argentina',
    'portal de noticias argentino'
  ];

  const anchorText = anchorTextOptions[Math.floor(Math.random() * anchorTextOptions.length)];

  // Insert link naturally into article
  const article = $input.item.json.article;
  const sentences = article.split('.');
  const randomSentenceIndex = Math.floor(Math.random() * (sentences.length - 2)) + 1; // Not first or last

  sentences[randomSentenceIndex] += ` Para más detalles, visita <a href="https://politica-argentina.com" rel="nofollow">${anchorText}</a>.`;

  $input.item.json.article = sentences.join('.');
  $input.item.json.link_added = true;
  $input.item.json.anchor_text = anchorText;
} else {
  $input.item.json.link_added = false;
}

return $input.item;
